using System;\nusing System.Collections.Specialized;\nusing System.IO;\nusing System.Web;\nusing System.Web.UI;\nusing Moq;\nusing OWASP.WebGoat.NET;\nusing OWASP.WebGoat.NET.App_Code.DB;\nusing Xunit;\n\nnamespace OWASP.WebGoat.NET.Tests\n{\n    public class ForgotPasswordCookieFlagsTests\n    {\n        [Fact]\n        public void ButtonCheckEmailClick_SetsSecurityAnswerCookie_HttpOnlyEnabled()\n        {\n            // Arrange: create page and inject DB provider\n            var page = new ForgotPassword();\n\n            var mockDb = new Mock<IDbProvider>();\n            mockDb.Setup(d => d.GetSecurityQuestionAndAnswer(It.IsAny<string>()))\n                  .Returns(new[] { \"Question?\", \"answer\" });\n\n            // set private field 'du'\n            var duField = typeof(ForgotPassword).GetField(\"du\", BindingFlags.Instance | BindingFlags.NonPublic);\n            Assert.NotNull(duField);\n            duField!.SetValue(page, mockDb.Object);\n\n            // HttpContext needed for Response.Cookies\n            var httpCtx = new HttpContext(\n                new HttpRequest(\"\", \"http://localhost/\", \"\"),\n                new HttpResponse(new StringWriter()));\n            HttpContext.Current = httpCtx;\n\n            // set required controls via reflection\n            SetPrivateControl(page, \"txtEmail\", new System.Web.UI.WebControls.TextBox { Text = \"a@b.com\" });\n            SetPrivateControl(page, \"labelQuestion\", new System.Web.UI.WebControls.Label());\n            SetPrivateControl(page, \"PanelForgotPasswordStep2\", new System.Web.UI.WebControls.Panel());\n            SetPrivateControl(page, \"PanelForgotPasswordStep3\", new System.Web.UI.WebControls.Panel());\n\n            // Act\n            InvokeNonPublic(page, \"ButtonCheckEmail_Click\", page, EventArgs.Empty);\n\n            // Assert\n            var cookie = httpCtx.Response.Cookies[\"encr_sec_qu_ans\"];\n            Assert.NotNull(cookie);\n            Assert.True(cookie!.HttpOnly);\n        }\n\n        private static void SetPrivateControl(object page, string fieldName, object control)\n        {\n            var f = page.GetType().GetField(fieldName, BindingFlags.Instance | BindingFlags.NonPublic);\n            Assert.NotNull(f);\n            f!.SetValue(page, control);\n        }\n\n        private static void InvokeNonPublic(object obj, string methodName, params object[] args)\n        {\n            var m = obj.GetType().GetMethod(methodName, BindingFlags.Instance | BindingFlags.NonPublic);\n            Assert.NotNull(m);\n            m!.Invoke(obj, args);\n        }\n    }\n}\n